import{_ as t,o as e,c as a,ae as l}from"./chunks/framework.EHGTsUvI.js";const h=JSON.parse('{"title":"面向对象","description":"","frontmatter":{},"headers":[],"relativePath":"coding/java/object.md","filePath":"coding/java/object.md"}'),r={name:"coding/java/object.md"};function c(n,o,s,i,u,d){return e(),a("div",null,[...o[0]||(o[0]=[l('<h1 id="面向对象" tabindex="-1">面向对象 <a class="header-anchor" href="#面向对象" aria-label="Permalink to &quot;面向对象&quot;">​</a></h1><h2 id="_1、对象导论" tabindex="-1">1、对象导论 <a class="header-anchor" href="#_1、对象导论" aria-label="Permalink to &quot;1、对象导论&quot;">​</a></h2><ul><li><strong>万物皆为对象</strong>: 将对象视为奇特的变量，它可以存储数据，除此之外，你还可以要求它在自身上执行操作，理论上讲，你可以抽取待求解问题的任何概念化构件（狗，建筑物，服务等），将其表示为程序中的对象</li><li><strong>程序是对象的集合，它们通过发送消息来告知彼此所要做的</strong>: 要想请求一个对象，就必须对该对象发送一条信息。更具体说，可以把消息想象为对某个特定对象的方法的调用请求。</li><li><strong>每个对象都拥有其类型</strong>: 按照通用的说法，每个对象都是某个类（<code>class</code>）的一个实例（<code>instance</code>），这里 <strong><code>类</code></strong> 就是 <strong><code>类型</code></strong> 的同义词。每个类最重要的区别在于其他类的特性就是&quot;可以发送什么样的消息给它&quot;</li><li><strong>某一特定类型的所有对象都可以接收同样的消息</strong>: 这是一句意味深长的表述，你在稍后便会看到，因为&quot;圆形&quot;类型的额对象同时也是&quot;几何形&quot;类型的对象，所以一个&quot;圆形&quot;对象必定能够接受发送给&quot;几何形&quot;对象的消息。这意味着可以编写与&quot;几何形&quot;交互并自动处理所有与几何形性质相关的事物的代码，这种可替代性是OOP中最强有力的概念之一</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>对象具有状态、行为和标识。这意味着每一个对象抵都可以拥有内部数据（它们给出了该对象的状态）和方法（它们产生行为），并且每一个对象都可以唯一的与其他对象区分开来，具体来说就是每一个对象在内存中 都有一个唯一的地址</p></div><h2 id="_2、一切都是对象" tabindex="-1">2、一切都是对象 <a class="header-anchor" href="#_2、一切都是对象" aria-label="Permalink to &quot;2、一切都是对象&quot;">​</a></h2><p><strong>对象如何创建？</strong><br>  <strong><code>new</code></strong> 关键字，String s = new String(&quot;abc&quot;);</p><p><strong>创建后的对象存储在哪？</strong></p><blockquote><p>程序运行时，对象是怎么进行放置安排的，特别是内存是怎样分配的？</p></blockquote><ul><li><strong><code>寄存器</code></strong></li></ul><blockquote><p>最快的存储区，位于处理器内部，，寄存器数量极其有限，所以寄存器根据需求进行分配，不能直接控制，也不能在程序中感觉到寄存器存在的任何迹象</p></blockquote><ul><li><strong><code>堆栈</code></strong></li></ul><blockquote><p>位于通用RAM（随机访问存储器）中，但通过堆栈指针可以从处理器那里获得直接支持，堆栈指针若向下移动，则分配新的内存，若向上移动，则释放那些内存，这是一种有效的快速存储方法，效率仅次于寄存器，创建程序时</p></blockquote><ul><li><strong><code>堆</code></strong></li></ul><blockquote></blockquote><ul><li><strong><code>常量存储</code></strong></li></ul><blockquote></blockquote><ul><li><strong><code>非RAM存储</code></strong></li></ul><blockquote></blockquote><h2 id="_3、多态" tabindex="-1">3、多态 <a class="header-anchor" href="#_3、多态" aria-label="Permalink to &quot;3、多态&quot;">​</a></h2><h2 id="_4、接口" tabindex="-1">4、接口 <a class="header-anchor" href="#_4、接口" aria-label="Permalink to &quot;4、接口&quot;">​</a></h2><h2 id="_5、内部类" tabindex="-1">5、内部类 <a class="header-anchor" href="#_5、内部类" aria-label="Permalink to &quot;5、内部类&quot;">​</a></h2><h2 id="_6、持有对象" tabindex="-1">6、持有对象 <a class="header-anchor" href="#_6、持有对象" aria-label="Permalink to &quot;6、持有对象&quot;">​</a></h2>',22)])])}const b=t(r,[["render",c]]);export{h as __pageData,b as default};
